if (_Hb?.registerPartial && _Hb?.compile) {
  const _t = {
  "modules/Pf2eNationsAndCitiesMaker/templates/builder.html": "<div class=\"npc-builder-layout\">\n\n  <!-- ── Tab strip (Home + this module's builder) ──────────────────────── -->\n  <div class=\"builder-tabs\">\n    <button type=\"button\" class=\"builder-tab builder-tab--home\" data-tab=\"home\">\n      <i class=\"fa-solid fa-house\"></i> Home\n    </button>\n    <div class=\"builder-tab-group\">\n      <button type=\"button\" class=\"builder-tab builder-tab--builder\" data-tab=\"builder\">\n        <i class=\"{{module.icon}}\"></i> {{module.label}}\n      </button>\n      <a href=\"{{module.githubUrl}}\" target=\"_blank\" rel=\"noopener noreferrer\" class=\"builder-tab-github\" title=\"View on GitHub\" aria-label=\"View module on GitHub\">\n        <i class=\"fa-brands fa-github\"></i>\n      </a>\n    </div>\n  </div>\n\n  <!-- ── Home panel (links to all 4 modules) ──────────────────────────── -->\n  <div class=\"home-panel\" style=\"display:none;\">\n    <div class=\"home-content\">\n      <div class=\"home-logo\">\n        <i class=\"fa-solid fa-wand-magic-sparkles\"></i>\n        <h2>CferNpcMaker — {{module.label}}</h2>\n      </div>\n\n      <!-- Getting Started / Instructions -->\n      <div class=\"home-instructions\">\n        <div class=\"home-instructions-header\">\n          <i class=\"fa-solid fa-circle-info\"></i>\n          <h3>Getting Started</h3>\n        </div>\n        <ol class=\"home-instructions-steps\">\n          <li>\n            <strong>Sign in with Patreon.</strong>\n            Click <em>Sign in with Patreon</em> in the builder to authenticate.\n          </li>\n          <li>\n            <strong>Open the <i class=\"{{module.icon}}\"></i> {{module.label}} tab</strong> at the top of this window to reach the form.\n          </li>\n          <li>\n            <strong>Describe your {{documentNoun}}.</strong>\n            Fill in a name, level, and description — the more detail you provide, the better the result.\n          </li>\n          <li>\n            <strong>Click Generate.</strong>\n            Your new {{documentNoun}} is added to Foundry and appears in the history panel on the right.\n          </li>\n        </ol>\n        <p class=\"home-instructions-tip\">\n          <i class=\"fa-solid fa-lightbulb\"></i>\n          Click any past entry in the history panel to re-populate the form and tweak it.\n        </p>\n      </div>\n\n      <p class=\"home-intro\">\n        You're using <strong>{{module.label}}</strong>. The CferNpcMaker family ships\n        a separate Foundry module for each system so each install only contains the\n        code it needs. Install any of the others to round out your toolset.\n      </p>\n\n      <div class=\"home-modules-grid\">\n        {{#each homeModules}}\n        <div class=\"home-module-card {{accentClass}}{{#if isCurrent}} home-module-card--current{{/if}}\">\n          <div class=\"home-module-icon\"><i class=\"{{icon}}\"></i></div>\n          <div class=\"home-module-body\">\n            <div class=\"home-module-title\">{{label}}</div>\n            <div class=\"home-module-desc\">{{description}}</div>\n          </div>\n          <div class=\"home-module-cta\">\n            {{#if isCurrent}}\n              <span class=\"home-module-current-badge\"><i class=\"fa-solid fa-check\"></i> Installed</span>\n            {{else}}\n              <a href=\"{{install}}\" target=\"_blank\" rel=\"noopener noreferrer\" class=\"home-module-install\">\n                <i class=\"fa-brands fa-github\"></i> Install\n              </a>\n            {{/if}}\n          </div>\n        </div>\n        {{/each}}\n      </div>\n\n      <!-- Custom art style -->\n      <div class=\"home-art-style\">\n        <label for=\"npc-art-style\" class=\"home-art-style-label\">\n          <i class=\"fa-solid fa-palette\"></i>\n          <span>Custom Art Style</span>\n        </label>\n        <input type=\"text\" id=\"npc-art-style\" class=\"home-art-style-input\"\n          placeholder=\"e.g. watercolor fantasy, anime, oil painting, comic book…\" />\n        <span class=\"home-art-style-hint\">\n          Specify an art style for generated NPC images. Leave blank to use the system default.\n        </span>\n      </div>\n\n      <div class=\"home-links\">\n        <a href=\"https://discord.gg/6AJxmtjZvX\" target=\"_blank\" rel=\"noopener noreferrer\" class=\"btn-discord\">\n          <i class=\"fa-brands fa-discord\"></i> Join our Discord\n        </a>\n        <a href=\"https://www.patreon.com/cw/CelestiaTools\" target=\"_blank\" rel=\"noopener noreferrer\" class=\"btn-patreon-link\">\n          <i class=\"fa-brands fa-patreon\"></i> Support on Patreon\n        </a>\n      </div>\n    </div>\n  </div>\n\n  <!-- ── Offline detection banner ────────────────────────────────────── -->\n  <div class=\"offline-banner\" style=\"display:none;\" role=\"status\" aria-live=\"polite\">\n    <i class=\"fa-solid fa-wifi\" aria-hidden=\"true\"></i>\n    <span>No network connection — generation is unavailable until you're back online.</span>\n  </div>\n\n  <!-- ── Main builder content ─────────────────────────────────────────── -->\n  <div class=\"builder-inner\">\n\n    <!-- Left: form panel -->\n    <div class=\"npc-panel-form\">\n\n      <!-- Auth banner -->\n      <div class=\"auth-banner\">\n        <div class=\"auth-unsigned\">\n          <div class=\"auth-unsigned-text\">\n            <i class=\"fa-brands fa-patreon auth-patreon-icon\"></i>\n            <span>Sign in with Patreon to use this module</span>\n          </div>\n          <div class=\"auth-unsigned-actions\">\n            <button type=\"button\" data-action=\"signin\" class=\"btn-patreon\">\n              <i class=\"fa-brands fa-patreon\"></i> Sign in with Patreon\n            </button>\n            <button type=\"button\" data-action=\"patreon\" class=\"btn-join\">\n              Join Patreon\n            </button>\n          </div>\n        </div>\n        <div class=\"auth-signed\">\n          <div class=\"auth-signed-status\">\n            <i class=\"fa-solid fa-circle-check\"></i>\n            <span>Signed in via Patreon</span>\n          </div>\n          <button type=\"button\" data-action=\"signout\" class=\"btn-signout\">\n            <i class=\"fa-solid fa-right-from-bracket\"></i> Sign Out\n          </button>\n        </div>\n      </div>\n\n      <!-- Module-specific form -->\n      <form class=\"npc-form settlement-form\" autocomplete=\"off\">\n\n        <div class=\"history-selected-banner\" style=\"display:none;\">\n          <i class=\"fa-solid fa-arrow-turn-up fa-rotate-90\"></i>\n          <span class=\"history-selected-label\">Editing prompt from <strong></strong> — update fields and Generate to recreate</span>\n        </div>\n\n        <div class=\"settlement-template-row\">\n          <div class=\"field field--template\">\n            <label for=\"settlement-template\">Template</label>\n            <select id=\"settlement-template\" name=\"template\" class=\"settlement-template-select\">\n              <option value=\"custom\">— Custom —</option>\n              <option value=\"farming-village\">Sleepy farming village</option>\n              <option value=\"river-trade-town\">Bustling river-trade town</option>\n              <option value=\"frontier-outpost\">Fortified frontier outpost</option>\n              <option value=\"coastal-port\">Coastal fishing port</option>\n              <option value=\"desert-waystation\">Desert caravan waystation</option>\n              <option value=\"dwarven-hold\">Mountain dwarven hold</option>\n              <option value=\"elven-enclave\">Elven forest enclave</option>\n              <option value=\"capital-city\">Walled capital city</option>\n              <option value=\"mining-boomtown\">Mining boomtown</option>\n              <option value=\"temple-town\">Pilgrim temple-town</option>\n            </select>\n          </div>\n          <button type=\"button\" class=\"btn-randomize-settlement\" title=\"Pick a random template and roll a name\">\n            <i class=\"fa-solid fa-dice-d20\"></i> Randomize Settlement\n          </button>\n        </div>\n\n        <div class=\"field-row\">\n          <div class=\"field field--name field--with-button\">\n            <label for=\"settlement-name\">Settlement Name</label>\n            <div class=\"input-with-button\">\n              <input type=\"text\" id=\"settlement-name\" name=\"name\" placeholder=\"e.g. Ashford\" />\n              <button type=\"button\" class=\"btn-roll-name\" title=\"Roll a thematic name\">\n                <i class=\"fa-solid fa-dice\"></i>\n              </button>\n            </div>\n          </div>\n          <div class=\"field field--kind\">\n            <label for=\"settlement-kind\">Kind</label>\n            <select id=\"settlement-kind\" name=\"kind\">\n              <option value=\"village\">Village</option>\n              <option value=\"town\" selected>Town</option>\n              <option value=\"city\">City</option>\n              <option value=\"nation\">Nation</option>\n            </select>\n          </div>\n          <div class=\"field field--size\">\n            <label for=\"settlement-size\">Size</label>\n            <select id=\"settlement-size\" name=\"size\">\n              <option value=\"thorp\">Thorp</option>\n              <option value=\"hamlet\">Hamlet</option>\n              <option value=\"village\">Village</option>\n              <option value=\"town\" selected>Town</option>\n              <option value=\"city\">City</option>\n              <option value=\"metropolis\">Metropolis</option>\n            </select>\n          </div>\n        </div>\n\n        <div class=\"field-row\">\n          <div class=\"field\">\n            <label for=\"settlement-biome\">Biome / setting</label>\n            <input type=\"text\" id=\"settlement-biome\" name=\"biome\" placeholder=\"e.g. coastal, mountain, forest\" />\n          </div>\n          <div class=\"field\">\n            <label for=\"settlement-population\">Population (optional)</label>\n            <input type=\"number\" id=\"settlement-population\" name=\"populationHint\" min=\"0\" step=\"50\" placeholder=\"auto\" />\n          </div>\n        </div>\n\n        <div class=\"field\">\n          <label for=\"settlement-government\">Government hint (optional)</label>\n          <input type=\"text\" id=\"settlement-government\" name=\"governmentHint\" placeholder=\"e.g. Mayor + merchant guild\" />\n        </div>\n\n        <div class=\"field\">\n          <label for=\"settlement-desc\">Description</label>\n          <select class=\"desc-template-select\" aria-label=\"Load a description template\">\n            <option value=\"\">— Quick template… —</option>\n            <option value=\"A raw, fast-growing boomtown that sprang up around a fresh ore strike six months ago. Saloons and assay offices outnumber churches; the main street is churned mud, and tents jostle with hastily-built timber storefronts. Governance is loose — a committee of the three richest claim-holders calls itself the council. Claim-jumpers, desperate prospectors, and opportunistic merchants all rub elbows; violence is a nightly occurrence and the rule of law is negotiable.\">Frontier mining camp</option>\n            <option value=\"A low-lying waterfront quarter laced with canals and footbridges, built on pilings above the tideline after the old harbour silted in. Half the shopfronts open onto stilted boardwalks instead of streets, and gondoliers pole goods between them at high tide when the lower lanes flood. The air smells of brine and wet timber; eel-traps and mooring posts crowd every canal-front stoop. Flooding is routine enough that shutters double as makeshift levees, and the poorer stilt-houses lean on their neighbours for support — both literally and in the tight-knit, mutually suspicious way locals look out for their own.\">Sunken canal district</option>\n          </select>\n          <textarea id=\"settlement-desc\" name=\"description\" rows=\"5\"\n            placeholder=\"Describe this settlement: its mood, economy, notable features, conflicts, who lives here…\"></textarea>\n          <span class=\"field-hint\">The more detail you provide, the more textured the result.</span>\n        </div>\n\n        <div class=\"field-row settlement-checks\">\n          <label class=\"checkbox-label\">\n            <input type=\"checkbox\" name=\"includeStores\" checked />\n            <span>Generate stores</span>\n          </label>\n          <label class=\"checkbox-label\">\n            <input type=\"checkbox\" name=\"includeMilitary\" checked />\n            <span>Generate guards / military</span>\n          </label>\n          <label class=\"checkbox-label\">\n            <input type=\"checkbox\" name=\"includeLeadership\" checked />\n            <span>Generate leadership</span>\n          </label>\n        </div>\n\n        <div class=\"form-actions\">\n          <button type=\"button\" data-action=\"generate\" class=\"btn-primary\" disabled>\n            <i class=\"fa-solid fa-wand-magic-sparkles\"></i>\n            <span class=\"btn-label\">Generate Settlement</span>\n          </button>\n          <button type=\"button\" data-action=\"export\" class=\"btn-secondary\" disabled>\n            <i class=\"fa-solid fa-file-arrow-down\"></i>\n            <span>Export JSON</span>\n          </button>\n        </div>\n        <p class=\"settlement-cost-hint\" id=\"settlement-cost-hint\" aria-live=\"polite\"></p>\n\n      </form>\n\n      <div class=\"post-gen-actions\">\n        <button type=\"button\" data-action=\"undolast\" class=\"btn-undo\" disabled>\n          <i class=\"fa-solid fa-rotate-left\" aria-hidden=\"true\"></i>\n          <span>Undo Last Generation</span>\n        </button>\n      </div>\n    </div>\n\n    <!-- Right: history panel -->\n    <div class=\"npc-panel-history\">\n      <div class=\"history-header\">\n        <i class=\"fa-solid fa-clock-rotate-left\"></i>\n        <span class=\"history-header-label\">{{module.historyLabel}}</span>\n        <button type=\"button\" class=\"history-compact-btn\" title=\"Collapse history panel\" aria-pressed=\"false\" aria-label=\"Toggle compact history panel\">\n          <i class=\"fa-solid fa-angles-right\"></i>\n        </button>\n        <button type=\"button\" class=\"history-clear-btn\" data-action=\"clearhistory\" title=\"Clear all history entries\">\n          <i class=\"fa-solid fa-trash-can\"></i>\n        </button>\n      </div>\n      <div class=\"history-search\">\n        <input type=\"text\" class=\"history-search-input\" placeholder=\"Filter by name…\" aria-label=\"Filter history by name\">\n      </div>\n      <div class=\"history-list\"></div>\n    </div>\n\n  </div>\n\n  <!-- ── Feedback section ─────────────────────────────────────────────── -->\n  <div class=\"feedback-section\">\n    <div class=\"feedback-header\">\n      <i class=\"fa-solid fa-comment-dots\"></i>\n      <span>Send Feedback</span>\n    </div>\n    <div class=\"feedback-body\">\n      <textarea class=\"feedback-textarea\" placeholder=\"Found a bug? Have a suggestion? Let us know…\" rows=\"2\"></textarea>\n      <button type=\"button\" data-action=\"sendfeedback\" class=\"feedback-send-btn\">\n        <i class=\"fa-solid fa-paper-plane\"></i>\n        <span>Send</span>\n      </button>\n    </div>\n    <div class=\"feedback-status\" style=\"display:none;\"></div>\n  </div>\n\n</div>\n",
  "modules/Pf2eNationsAndCitiesMaker/templates/city-sheet.hbs": "<div class=\"pf2e-settlement\">\n\n  <div class=\"pf2e-settlement-header\">\n    <div class=\"pf2e-settlement-title\">\n      <i class=\"fa-solid fa-city\"></i>\n      <h2>{{doc.name}}</h2>\n      <span class=\"pf2e-settlement-kind-pill\">{{settlement.kind}} · {{settlement.size}}</span>\n    </div>\n    <div class=\"pf2e-settlement-header-actions\">\n      {{#if calendarActive}}\n        <span class=\"pf2e-tag pf2e-tag--ok\"><i class=\"fa-solid fa-calendar-check\"></i> Calendar linked</span>\n      {{else}}\n        <button type=\"button\" data-action=\"tickDay\"><i class=\"fa-solid fa-sun\"></i> Tick Day</button>\n        <button type=\"button\" data-action=\"tickWeek\"><i class=\"fa-solid fa-calendar-week\"></i> Tick Week</button>\n      {{/if}}\n      <button type=\"button\" data-action=\"manualTax\"><i class=\"fa-solid fa-coins\"></i> Apply Tax</button>\n      <button type=\"button\" data-action=\"exportHandout\"><i class=\"fa-solid fa-file-arrow-down\"></i> Export Handout</button>\n      <button type=\"button\" data-action=\"openBuilder\"><i class=\"fa-solid fa-wand-magic-sparkles\"></i> Open Builder</button>\n    </div>\n  </div>\n\n  <div class=\"pf2e-settlement-body\">\n\n    <nav class=\"pf2e-settlement-tabs\">\n      {{#each tabs}}\n        <button type=\"button\"\n                class=\"pf2e-settlement-tab{{#if isActive}} is-active{{/if}}\"\n                data-action=\"switchTab\" data-tab=\"{{key}}\">\n          <i class=\"{{icon}}\"></i> {{label}}\n        </button>\n      {{/each}}\n    </nav>\n\n    <section class=\"pf2e-settlement-tab-body\">\n\n      {{#if isOverviewActive}}\n        {{> \"modules/Pf2eNationsAndCitiesMaker/templates/partials/statblock.hbs\"\n            settlement=settlement hpPct=hpPct moralePct=moralePct unrestPct=unrestPct\n            sparklineSvg=sparklineSvg}}\n      {{/if}}\n\n      {{#if isStoresActive}}\n        {{> \"modules/Pf2eNationsAndCitiesMaker/templates/partials/stores-tab.hbs\"\n            settlement=settlement storeTabs=storeTabs storeTypeOptions=storeTypeOptions\n            canGenerateNpc=canGenerateNpc canGenerateItem=canGenerateItem}}\n      {{/if}}\n\n      {{#if isGuardsActive}}\n        {{> \"modules/Pf2eNationsAndCitiesMaker/templates/partials/guards-tab.hbs\"\n            settlement=settlement canGenerateNpc=canGenerateNpc}}\n      {{/if}}\n\n      {{#if isLeadershipActive}}\n        {{> \"modules/Pf2eNationsAndCitiesMaker/templates/partials/leadership-tab.hbs\"\n            settlement=settlement canGenerateNpc=canGenerateNpc}}\n      {{/if}}\n\n      {{#if isProductionActive}}\n        {{> \"modules/Pf2eNationsAndCitiesMaker/templates/partials/production-tab.hbs\"\n            settlement=settlement tradeGoods=tradeGoods priceMultiplier=priceMultiplier\n            settlementJournals=settlementJournals}}\n      {{/if}}\n\n      {{#if isNotesActive}}\n        <div class=\"pf2e-settlement-notes\">\n          <textarea data-settlement-path=\"notes\" rows=\"20\" placeholder=\"Freeform notes about this settlement (history, rumours, hooks…)\">{{settlement.notes}}</textarea>\n          <button type=\"button\" class=\"pf2e-settlement-btn\" data-action=\"saveNotes\"><i class=\"fa-solid fa-floppy-disk\"></i> Save notes</button>\n        </div>\n      {{/if}}\n\n    </section>\n\n  </div>\n</div>\n",
  "modules/Pf2eNationsAndCitiesMaker/templates/nation-sheet.hbs": "<div class=\"pf2e-nation\">\n\n  <div class=\"pf2e-nation-header\">\n    <i class=\"fa-solid fa-flag\"></i>\n    <h2>{{doc.name}}</h2>\n    <span class=\"pf2e-settlement-kind-pill\">Nation</span>\n  </div>\n\n  <div class=\"pf2e-nation-summary\">\n    <div class=\"pf2e-nation-stat\"><label>Population (sum)</label><span>{{totals.population}}</span></div>\n    <div class=\"pf2e-nation-stat\"><label>Treasury (sum gp)</label><span>{{totals.treasuryGp}}</span></div>\n    <div class=\"pf2e-nation-stat\"><label>Guards (sum)</label><span>{{totals.guards}}</span></div>\n  </div>\n\n  <h3><i class=\"fa-solid fa-crown\"></i> Government</h3>\n  <div class=\"pf2e-nation-government\">\n    <label>Type\n      <input type=\"text\" data-path=\"government.type\" data-action=\"saveField\" value=\"{{nation.government.type}}\" />\n    </label>\n    <label>Head of state\n      <input type=\"text\" data-path=\"government.leaderName\" data-action=\"saveField\" value=\"{{nation.government.leaderName}}\" />\n    </label>\n  </div>\n\n  <h3><i class=\"fa-solid fa-city\"></i> Cities</h3>\n  {{#if cities.length}}\n    <table class=\"pf2e-nation-cities\">\n      <thead><tr><th>Name</th><th>Kind</th><th>Population</th><th>HP%</th><th>Treasury (gp)</th><th>Guards</th><th></th></tr></thead>\n      <tbody>\n        {{#each cities}}\n          <tr>\n            <td><a href=\"#\" data-action=\"openChildCity\" data-city-id=\"{{id}}\">{{name}}</a></td>\n            <td>{{kind}}</td>\n            <td>{{population}}</td>\n            <td>{{hpPct}}%</td>\n            <td>{{treasuryGp}}</td>\n            <td>{{guards}}</td>\n            <td>\n              <button type=\"button\" class=\"pf2e-icon-btn pf2e-icon-btn--danger\"\n                      data-action=\"removeChildCity\" data-city-id=\"{{id}}\" title=\"Detach from nation\">\n                <i class=\"fa-solid fa-link-slash\"></i>\n              </button>\n            </td>\n          </tr>\n        {{/each}}\n      </tbody>\n    </table>\n  {{else}}\n    <em class=\"pf2e-empty\">No cities linked to this nation yet.</em>\n  {{/if}}\n\n  <div class=\"pf2e-nation-add-city\">\n    <select name=\"addCityId\">\n      {{#if availableJournals.length}}\n        {{#each availableJournals}}<option value=\"{{id}}\">{{name}}</option>{{/each}}\n      {{else}}\n        <option value=\"\">— no candidate settlements —</option>\n      {{/if}}\n    </select>\n    <button type=\"button\" class=\"pf2e-settlement-btn\" data-action=\"addChildCity\">\n      <i class=\"fa-solid fa-link\"></i> Link City\n    </button>\n  </div>\n\n  <h3><i class=\"fa-solid fa-scroll\"></i> Notes</h3>\n  <textarea data-path=\"notes\" rows=\"8\">{{nation.notes}}</textarea>\n  <button type=\"button\" class=\"pf2e-settlement-btn\" data-action=\"saveNotes\">\n    <i class=\"fa-solid fa-floppy-disk\"></i> Save notes\n  </button>\n\n</div>\n",
  "modules/Pf2eNationsAndCitiesMaker/templates/partials/guards-tab.hbs": "{{#if showMilitary}}\n<div class=\"pf2e-guards\">\n\n  <div class=\"pf2e-guards-summary\">\n    <div class=\"pf2e-guards-total\">\n      <i class=\"fa-solid fa-shield-halved\"></i>\n      <span>{{settlement.military.totalGuards}} guards total</span>\n    </div>\n    {{#if totalDailyWages}}\n      <div class=\"pf2e-guards-wages\">\n        <i class=\"fa-solid fa-coins\"></i>\n        <span>{{totalDailyWages}} gp/day wages</span>\n      </div>\n    {{/if}}\n    <div class=\"pf2e-commander\">\n      <label>Commander</label>\n      <input type=\"text\" data-settlement-path=\"military.commanderName\" value=\"{{settlement.military.commanderName}}\" />\n      {{#if settlement.military.commanderActorId}}\n        <button type=\"button\" class=\"pf2e-icon-btn\"\n                data-action=\"openLinkedActor\" data-actor-id=\"{{settlement.military.commanderActorId}}\" title=\"Open commander\">\n          <i class=\"fa-solid fa-user\"></i>\n        </button>\n      {{/if}}\n      {{#if canGenerateNpc}}\n        <button type=\"button\" class=\"pf2e-settlement-btn\" data-action=\"generateCommander\">\n          <i class=\"fa-solid fa-wand-magic-sparkles\"></i> Generate Commander\n        </button>\n      {{/if}}\n    </div>\n  </div>\n\n  <h4><i class=\"fa-solid fa-bars-staggered\"></i> Rank Pyramid</h4>\n  <table class=\"pf2e-rank-table\">\n    <thead><tr><th>Rank</th><th>Count</th><th>Wage (gp/day)</th><th>Lead</th><th></th></tr></thead>\n    <tbody>\n      {{#each settlement.military.ranks}}\n        <tr>\n          <td><input type=\"text\"   data-settlement-path=\"military.ranks.{{@index}}.rank\"       value=\"{{rank}}\" /></td>\n          <td><input type=\"number\" min=\"0\" data-settlement-path=\"military.ranks.{{@index}}.count\" value=\"{{count}}\" /></td>\n          <td><input type=\"number\" min=\"0\" step=\"0.1\" data-settlement-path=\"military.ranks.{{@index}}.dailyWage\" value=\"{{dailyWage}}\" /></td>\n          <td><input type=\"text\"   data-settlement-path=\"military.ranks.{{@index}}.leaderName\" value=\"{{leaderName}}\" /></td>\n          <td>\n            <button type=\"button\" class=\"pf2e-icon-btn pf2e-icon-btn--danger\"\n                    data-action=\"removeRank\" data-index=\"{{@index}}\" title=\"Remove rank\">\n              <i class=\"fa-solid fa-xmark\"></i>\n            </button>\n          </td>\n        </tr>\n      {{/each}}\n    </tbody>\n  </table>\n  <button type=\"button\" class=\"pf2e-settlement-btn\" data-action=\"addRank\">\n    <i class=\"fa-solid fa-plus\"></i> Add Rank\n  </button>\n\n</div>\n{{else}}\n<div class=\"pf2e-empty-state\">\n  <i class=\"fa-solid fa-eye-slash\"></i>\n  <p>Military information is restricted to the GM.</p>\n</div>\n{{/if}}\n",
  "modules/Pf2eNationsAndCitiesMaker/templates/partials/leadership-tab.hbs": "<div class=\"pf2e-leadership\">\n\n  <div class=\"pf2e-leadership-mayor\">\n    <h4><i class=\"fa-solid fa-crown\"></i> Head of {{settlement.kind}}</h4>\n    <div class=\"pf2e-leadership-mayor-row\">\n      <input type=\"text\" data-settlement-path=\"government.leaderName\" value=\"{{settlement.government.leaderName}}\" />\n      <input type=\"text\" data-settlement-path=\"government.type\"       value=\"{{settlement.government.type}}\" />\n    </div>\n  </div>\n\n  <h4><i class=\"fa-solid fa-user-group\"></i> Council</h4>\n  {{#if settlement.leadership.length}}\n    <ul class=\"pf2e-leadership-list\">\n      {{#each settlement.leadership}}\n        <li class=\"pf2e-leader-card\">\n          <input type=\"text\" class=\"pf2e-leader-title\" data-settlement-path=\"leadership.{{@index}}.title\" value=\"{{title}}\" />\n          <input type=\"text\" class=\"pf2e-leader-name\"  data-settlement-path=\"leadership.{{@index}}.name\"  value=\"{{name}}\" />\n          <input type=\"text\" class=\"pf2e-leader-role\"  data-settlement-path=\"leadership.{{@index}}.role\"  value=\"{{role}}\" placeholder=\"role / domain\" />\n          {{#if actorId}}\n            <button type=\"button\" class=\"pf2e-icon-btn\"\n                    data-action=\"openLinkedActor\" data-actor-id=\"{{actorId}}\" title=\"Open actor\">\n              <i class=\"fa-solid fa-user\"></i>\n            </button>\n          {{/if}}\n          {{#if ../canGenerateNpc}}\n            <button type=\"button\" class=\"pf2e-icon-btn\"\n                    data-action=\"generateLeader\" data-index=\"{{@index}}\" title=\"Generate NPC for this leader\">\n              <i class=\"fa-solid fa-wand-magic-sparkles\"></i>\n            </button>\n          {{/if}}\n          <button type=\"button\" class=\"pf2e-icon-btn pf2e-icon-btn--danger\"\n                  data-action=\"removeLeader\" data-index=\"{{@index}}\" title=\"Remove leader\">\n            <i class=\"fa-solid fa-xmark\"></i>\n          </button>\n        </li>\n      {{/each}}\n    </ul>\n  {{else}}\n    <em class=\"pf2e-empty\">No council members yet.</em>\n  {{/if}}\n\n  <button type=\"button\" class=\"pf2e-settlement-btn\" data-action=\"addLeader\">\n    <i class=\"fa-solid fa-user-plus\"></i> Add Council Member\n  </button>\n\n  <h4><i class=\"fa-solid fa-place-of-worship\"></i> Religions</h4>\n  {{#if settlement.religions.length}}\n    <ul class=\"pf2e-religion-list\">\n      {{#each settlement.religions}}\n        <li class=\"pf2e-religion-card\">\n          <input type=\"text\" class=\"pf2e-religion-name\"\n                 data-settlement-path=\"religions.{{@index}}.name\" value=\"{{name}}\" />\n          <label class=\"pf2e-religion-label\">Followers\n            <input type=\"number\" class=\"pf2e-religion-followers\"\n                   data-settlement-path=\"religions.{{@index}}.followers\" value=\"{{followers}}\" min=\"0\" />\n          </label>\n          <label class=\"pf2e-religion-label\">Influence\n            <input type=\"number\" class=\"pf2e-religion-influence\"\n                   data-settlement-path=\"religions.{{@index}}.influence\" value=\"{{influence}}\" min=\"0\" max=\"100\" />\n          </label>\n          <label class=\"pf2e-religion-label\">Temple\n            <select data-settlement-path=\"religions.{{@index}}.templeStoreId\" data-nullable-str>\n              <option value=\"\">— None —</option>\n              {{#each ../settlement.stores}}\n                {{#if (eqStr type \"temple\")}}\n                  <option value=\"{{id}}\" {{#if (eqStr id ../templeStoreId)}}selected{{/if}}>{{name}}</option>\n                {{/if}}\n              {{/each}}\n            </select>\n          </label>\n          <button type=\"button\" class=\"pf2e-icon-btn pf2e-icon-btn--danger\"\n                  data-action=\"removeReligion\" data-religion-id=\"{{id}}\" title=\"Remove religion\">\n            <i class=\"fa-solid fa-xmark\"></i>\n          </button>\n        </li>\n      {{/each}}\n    </ul>\n  {{else}}\n    <em class=\"pf2e-empty\">No religions tracked yet.</em>\n  {{/if}}\n\n  <button type=\"button\" class=\"pf2e-settlement-btn\" data-action=\"addReligion\">\n    <i class=\"fa-solid fa-plus\"></i> Add Religion\n  </button>\n</div>\n",
  "modules/Pf2eNationsAndCitiesMaker/templates/partials/production-tab.hbs": "<div class=\"pf2e-production\">\n\n  <h4><i class=\"fa-solid fa-wheat-awn\"></i> Production goods</h4>\n  {{#if settlement.production.length}}\n    <div class=\"pf2e-production-tags\">\n      {{#each settlement.production}}\n        <span class=\"pf2e-production-tag\">{{this}}</span>\n      {{/each}}\n    </div>\n  {{else}}\n    <em class=\"pf2e-empty\">No goods recorded yet.</em>\n  {{/if}}\n\n  {{#if tradeGoods.length}}\n    <h4><i class=\"fa-solid fa-book-open\"></i> Trade Goods Catalogue</h4>\n    <table class=\"pf2e-trade-goods-table\">\n      <thead>\n        <tr>\n          <th>Good</th>\n          <th>Base (gp)</th>\n          {{#if (neqNum priceMultiplier 1)}}\n            <th title=\"Base price × price multiplier\">Effective (gp)</th>\n          {{/if}}\n        </tr>\n      </thead>\n      <tbody>\n        {{#each tradeGoods}}\n          <tr>\n            <td>{{name}}</td>\n            <td>{{priceGp}}</td>\n            {{#if (neqNum ../priceMultiplier 1)}}\n              <td class=\"pf2e-effective-price\">{{effectivePrice}}</td>\n            {{/if}}\n          </tr>\n        {{/each}}\n      </tbody>\n    </table>\n  {{/if}}\n\n  <h4><i class=\"fa-solid fa-route\"></i> Trade Routes</h4>\n  {{#if settlement.tradeRoutes.length}}\n    <table class=\"pf2e-trade-routes-table\">\n      <thead>\n        <tr><th>Partner</th><th>Goods</th><th>GP / Week</th><th></th></tr>\n      </thead>\n      <tbody>\n        {{#each settlement.tradeRoutes}}\n          <tr>\n            <td>\n              <select data-settlement-path=\"tradeRoutes.{{@index}}.partnerId\"\n                      style=\"width:100%;padding:0.2em;border:1px solid #c2a070;background:#fffbef;border-radius:3px;\">\n                <option value=\"\">— none —</option>\n                {{#each ../settlementJournals}}\n                  <option value=\"{{id}}\"{{#if (eqStr id ../../partnerId)}} selected{{/if}}>{{name}}</option>\n                {{/each}}\n              </select>\n            </td>\n            <td>\n              <input type=\"text\" data-settlement-path=\"tradeRoutes.{{@index}}.goods\"\n                     value=\"{{goods}}\" placeholder=\"grain, iron…\"\n                     style=\"width:100%;padding:0.2em;border:1px solid #c2a070;background:#fffbef;border-radius:3px;\" />\n            </td>\n            <td>\n              <input type=\"number\" min=\"0\" data-settlement-path=\"tradeRoutes.{{@index}}.gpPerWeek\"\n                     value=\"{{gpPerWeek}}\"\n                     style=\"width:5em;padding:0.2em;border:1px solid #c2a070;background:#fffbef;border-radius:3px;\" />\n            </td>\n            <td>\n              <button type=\"button\" class=\"pf2e-icon-btn pf2e-icon-btn--danger\"\n                      data-action=\"removeTradeRoute\" data-index=\"{{@index}}\">\n                <i class=\"fa-solid fa-trash\"></i>\n              </button>\n            </td>\n          </tr>\n        {{/each}}\n      </tbody>\n    </table>\n  {{else}}\n    <em class=\"pf2e-empty\">No trade routes established.</em>\n  {{/if}}\n  <button type=\"button\" class=\"pf2e-settlement-btn\" data-action=\"addTradeRoute\"\n          style=\"margin-top:0.4em;\"><i class=\"fa-solid fa-plus\"></i> Add Route</button>\n\n  <h4><i class=\"fa-solid fa-coins\"></i> Treasury (live)</h4>\n  <table class=\"pf2e-treasury-table\">\n    <tbody>\n      <tr><th>CP</th><td>{{settlement.treasury.cp}}</td></tr>\n      <tr><th>SP</th><td>{{settlement.treasury.sp}}</td></tr>\n      <tr><th>GP</th><td>{{settlement.treasury.gp}}</td></tr>\n      <tr><th>PP</th><td>{{settlement.treasury.pp}}</td></tr>\n    </tbody>\n  </table>\n\n  <h4><i class=\"fa-solid fa-store\"></i> Store balances</h4>\n  {{#if settlement.stores.length}}\n    <table class=\"pf2e-store-balance-table\">\n      <thead><tr><th>Store</th><th>Type</th><th>Balance (gp)</th><th>Daily avg</th></tr></thead>\n      <tbody>\n        {{#each settlement.stores}}\n          <tr>\n            <td>{{name}}</td>\n            <td>{{type}}</td>\n            <td>{{income.balance}}</td>\n            <td>{{income.dailyAvg}}</td>\n          </tr>\n        {{/each}}\n      </tbody>\n    </table>\n  {{else}}\n    <em class=\"pf2e-empty\">No stores to balance.</em>\n  {{/if}}\n</div>\n",
  "modules/Pf2eNationsAndCitiesMaker/templates/partials/statblock.hbs": "<div class=\"pf2e-statblock\">\n\n  <div class=\"pf2e-statblock-row pf2e-statblock-row--top\">\n    <div class=\"pf2e-statblock-cell\">\n      <label>Population</label>\n      <input type=\"number\" min=\"0\" step=\"50\" data-settlement-path=\"population\" value=\"{{settlement.population}}\" />\n    </div>\n    <div class=\"pf2e-statblock-cell\">\n      <label>Biome</label>\n      <input type=\"text\" data-settlement-path=\"biome\" value=\"{{settlement.biome}}\" />\n    </div>\n    <div class=\"pf2e-statblock-cell\">\n      <label>Government</label>\n      <input type=\"text\" data-settlement-path=\"government.type\" value=\"{{settlement.government.type}}\" />\n    </div>\n    <div class=\"pf2e-statblock-cell\">\n      <label>Leader</label>\n      <input type=\"text\" data-settlement-path=\"government.leaderName\" value=\"{{settlement.government.leaderName}}\" />\n    </div>\n  </div>\n\n  <div class=\"pf2e-statblock-grid\">\n\n    <div class=\"pf2e-statblock-hp\">\n      <label>HP</label>\n      <div class=\"pf2e-hp-bar\"><div class=\"pf2e-hp-fill\" style=\"width:{{hpPct}}%;\"></div></div>\n      <div class=\"pf2e-hp-numbers\">\n        <input type=\"number\" min=\"0\" data-settlement-path=\"stats.hp\"    value=\"{{settlement.stats.hp}}\" />\n        <span class=\"pf2e-hp-sep\">/</span>\n        <input type=\"number\" min=\"1\" data-settlement-path=\"stats.maxHp\" value=\"{{settlement.stats.maxHp}}\" />\n      </div>\n    </div>\n\n    <div class=\"pf2e-stat-cell\">\n      <label>Damage Threshold</label>\n      <input type=\"number\" min=\"0\" data-settlement-path=\"stats.damageThreshold\" value=\"{{settlement.stats.damageThreshold}}\" />\n      <span class=\"pf2e-stat-hint\">Damage ≤ this is shrugged off.</span>\n    </div>\n    <div class=\"pf2e-stat-cell\">\n      <label>Hardness</label>\n      <input type=\"number\" min=\"0\" data-settlement-path=\"stats.hardness\" value=\"{{settlement.stats.hardness}}\" />\n      <span class=\"pf2e-stat-hint\">Flat reduction above threshold.</span>\n    </div>\n\n    <div class=\"pf2e-stat-cell\"><label>Fort</label>\n      <input type=\"number\" data-settlement-path=\"stats.fortitude\" value=\"{{settlement.stats.fortitude}}\" /></div>\n    <div class=\"pf2e-stat-cell\"><label>Ref</label>\n      <input type=\"number\" data-settlement-path=\"stats.reflex\"    value=\"{{settlement.stats.reflex}}\" /></div>\n    <div class=\"pf2e-stat-cell\"><label>Will</label>\n      <input type=\"number\" data-settlement-path=\"stats.will\"      value=\"{{settlement.stats.will}}\" /></div>\n\n    <div class=\"pf2e-stat-meter\">\n      <label>Morale</label>\n      <div class=\"pf2e-meter pf2e-meter--good\"><div style=\"width:{{moralePct}}%;\"></div></div>\n      <input type=\"number\" min=\"0\" max=\"100\" data-settlement-path=\"stats.morale\" value=\"{{settlement.stats.morale}}\" />\n    </div>\n    <div class=\"pf2e-stat-meter\">\n      <label>Unrest</label>\n      <div class=\"pf2e-meter pf2e-meter--bad\"><div style=\"width:{{unrestPct}}%;\"></div></div>\n      <input type=\"number\" min=\"0\" max=\"100\" data-settlement-path=\"stats.unrest\" value=\"{{settlement.stats.unrest}}\" />\n    </div>\n    <div class=\"pf2e-stat-cell\">\n      <label>Price Multiplier</label>\n      <input type=\"number\" min=\"0.1\" max=\"10\" step=\"0.05\"\n             data-settlement-path=\"priceMultiplier\"\n             value=\"{{settlement.priceMultiplier}}\"\n             title=\"Multiplied into all displayed prices (1.0 = normal; raise during sieges or inflation events)\" />\n    </div>\n    <div class=\"pf2e-stat-cell\">\n      <label>Growth Rate / day</label>\n      <input type=\"number\" min=\"0\" max=\"1\" step=\"0.0001\"\n             data-settlement-path=\"growthRate\"\n             value=\"{{settlement.growthRate}}\"\n             title=\"Population multiplier per day: growth × (1 − unrest%). Default 0.001.\" />\n    </div>\n    <div class=\"pf2e-stat-cell\">\n      <label>Crime Level (0–10)</label>\n      <input type=\"number\" min=\"0\" max=\"10\" step=\"1\"\n             data-settlement-path=\"crimeLevel\"\n             value=\"{{settlement.crimeLevel}}\"\n             title=\"Banditry/crime intensity. Each point leaks 0.5% of store balances daily and raises incident-report odds.\" />\n    </div>\n    {{#if settlement.famineDaysLeft}}\n    <div class=\"pf2e-stat-cell pf2e-stat-cell--famine\">\n      <label><i class=\"fa-solid fa-wheat-awn-circle-exclamation\"></i> Famine Days Left</label>\n      <input type=\"number\" min=\"0\" max=\"9999\" step=\"1\"\n             data-settlement-path=\"famineDaysLeft\"\n             value=\"{{settlement.famineDaysLeft}}\"\n             title=\"Days until the famine ends. Set to 0 to resolve immediately.\" />\n    </div>\n    {{/if}}\n  </div>\n\n  {{#if showTreasury}}\n  <div class=\"pf2e-statblock-treasury\">\n    <h4><i class=\"fa-solid fa-sack-dollar\"></i> Treasury</h4>\n    <div class=\"pf2e-treasury-row\">\n      <label>CP <input type=\"number\" min=\"0\" data-settlement-path=\"treasury.cp\" value=\"{{settlement.treasury.cp}}\" /></label>\n      <label>SP <input type=\"number\" min=\"0\" data-settlement-path=\"treasury.sp\" value=\"{{settlement.treasury.sp}}\" /></label>\n      <label>GP <input type=\"number\" min=\"0\" data-settlement-path=\"treasury.gp\" value=\"{{settlement.treasury.gp}}\" /></label>\n      <label>PP <input type=\"number\" min=\"0\" data-settlement-path=\"treasury.pp\" value=\"{{settlement.treasury.pp}}\" /></label>\n    </div>\n  </div>\n  {{#if sparklineSvg}}\n  <div class=\"pf2e-treasury-sparkline\">\n    <label>Treasury GP — last {{settlement.treasuryHistory.length}} days</label>\n    {{{sparklineSvg}}}\n  </div>\n  {{/if}}\n  {{/if}}\n\n  {{#if isGM}}\n  <div class=\"pf2e-gmonly-controls\">\n    <span class=\"pf2e-gmonly-label\"><i class=\"fa-solid fa-eye-slash\"></i> GM-only panels</span>\n    <label title=\"Hide treasury from players\">\n      <input type=\"checkbox\" data-settlement-path=\"gmOnly.treasury\" {{#if settlement.gmOnly.treasury}}checked{{/if}} />\n      Treasury\n    </label>\n    <label title=\"Hide Military tab from players\">\n      <input type=\"checkbox\" data-settlement-path=\"gmOnly.military\" {{#if settlement.gmOnly.military}}checked{{/if}} />\n      Military\n    </label>\n    <label title=\"Hide store income from players\">\n      <input type=\"checkbox\" data-settlement-path=\"gmOnly.income\" {{#if settlement.gmOnly.income}}checked{{/if}} />\n      Income\n    </label>\n  </div>\n  {{/if}}\n\n  <div class=\"pf2e-statblock-production\">\n    <h4><i class=\"fa-solid fa-wheat-awn\"></i> Produces</h4>\n    {{#if settlement.production.length}}\n      <div class=\"pf2e-production-tags\">\n        {{#each settlement.production}}\n          <span class=\"pf2e-production-tag\">{{this}}</span>\n        {{/each}}\n      </div>\n    {{else}}\n      <em class=\"pf2e-empty\">No recorded production.</em>\n    {{/if}}\n  </div>\n\n  <div class=\"pf2e-statblock-demographics\">\n    <div class=\"pf2e-demographics-header\">\n      <h4><i class=\"fa-solid fa-people-group\"></i> Demographics</h4>\n      <button type=\"button\" class=\"pf2e-icon-btn\" data-action=\"addDemographic\" title=\"Add ancestry row\">\n        <i class=\"fa-solid fa-plus\"></i>\n      </button>\n    </div>\n    {{#if settlement.demographics.length}}\n      <ul class=\"pf2e-demographics-list\">\n        {{#each settlement.demographics}}\n          <li class=\"pf2e-demographic-row\">\n            <input type=\"text\" class=\"pf2e-demographic-ancestry\"\n                   data-settlement-path=\"demographics.{{@index}}.ancestry\"\n                   value=\"{{ancestry}}\" placeholder=\"Ancestry…\" />\n            <input type=\"number\" class=\"pf2e-demographic-pct\"\n                   data-settlement-path=\"demographics.{{@index}}.pct\"\n                   value=\"{{pct}}\" min=\"0\" max=\"100\" />\n            <span class=\"pf2e-demographic-pct-label\">%</span>\n            <div class=\"pf2e-demographic-bar-wrap\">\n              <div class=\"pf2e-demographic-bar\" style=\"width:{{pct}}%;\"></div>\n            </div>\n            <button type=\"button\" class=\"pf2e-icon-btn pf2e-icon-btn--danger\"\n                    data-action=\"removeDemographic\" data-index=\"{{@index}}\" title=\"Remove\">\n              <i class=\"fa-solid fa-xmark\"></i>\n            </button>\n          </li>\n        {{/each}}\n      </ul>\n    {{else}}\n      <em class=\"pf2e-empty\">No demographics recorded — click + to add ancestries.</em>\n    {{/if}}\n  </div>\n\n</div>\n",
  "modules/Pf2eNationsAndCitiesMaker/templates/partials/stores-tab.hbs": "<div class=\"pf2e-stores\">\n\n  <div class=\"pf2e-stores-toolbar\">\n    <button type=\"button\" class=\"pf2e-settlement-btn\" data-action=\"addStore\">\n      <i class=\"fa-solid fa-plus\"></i> Add Store\n    </button>\n    <button type=\"button\" class=\"pf2e-settlement-btn\" data-action=\"rerollAllStores\"\n            title=\"Replace all stores with a new AI-generated set\">\n      <i class=\"fa-solid fa-dice\"></i> Re-roll All Stores\n    </button>\n    {{#if closedStoreCount}}\n      <button type=\"button\" class=\"pf2e-settlement-btn{{#if showClosed}} is-active{{/if}}\"\n              data-action=\"toggleShowClosed\">\n        <i class=\"fa-solid fa-store-slash\"></i>\n        {{#if showClosed}}Hide{{else}}Show{{/if}} Closed ({{closedStoreCount}})\n      </button>\n    {{/if}}\n    <button type=\"button\" class=\"pf2e-settlement-btn{{#if compactStores}} is-active{{/if}}\"\n            data-action=\"toggleCompactStores\" title=\"Toggle compact one-line store cards\">\n      <i class=\"fa-solid fa-list\"></i>\n      {{#if compactStores}}Expand{{else}}Compact{{/if}}\n    </button>\n    {{#if districts.length}}\n      <select data-district-filter class=\"pf2e-district-filter-select\" title=\"Filter stores by district\">\n        <option value=\"\">— All districts —</option>\n        {{#each districts}}\n          <option value=\"{{id}}\" {{#if (eqStr id ../districtFilter)}}selected{{/if}}>{{name}}</option>\n        {{/each}}\n      </select>\n    {{/if}}\n  </div>\n\n  <div class=\"pf2e-districts-section\">\n    <div class=\"pf2e-districts-header\">\n      <span><i class=\"fa-solid fa-map-location-dot\"></i> Districts</span>\n      <button type=\"button\" class=\"pf2e-icon-btn\" data-action=\"addDistrict\" title=\"Add district\">\n        <i class=\"fa-solid fa-plus\"></i>\n      </button>\n    </div>\n    {{#if districts.length}}\n      <ul class=\"pf2e-districts-list\">\n        {{#each districts}}\n          <li class=\"pf2e-district-row\">\n            <input type=\"text\" data-settlement-path=\"districts.{{@index}}.name\"\n                   value=\"{{name}}\" class=\"pf2e-district-name\" placeholder=\"District name…\" />\n            <input type=\"text\" data-settlement-path=\"districts.{{@index}}.descriptor\"\n                   value=\"{{descriptor}}\" class=\"pf2e-district-descriptor\" placeholder=\"descriptor…\" />\n            <button type=\"button\" class=\"pf2e-icon-btn pf2e-icon-btn--danger\"\n                    data-action=\"removeDistrict\" data-district-id=\"{{id}}\" title=\"Remove district\">\n              <i class=\"fa-solid fa-xmark\"></i>\n            </button>\n          </li>\n        {{/each}}\n      </ul>\n    {{/if}}\n  </div>\n\n  {{#if storeTabs.length}}\n    <nav class=\"pf2e-store-tabs\">\n      {{#each storeTabs}}\n        <button type=\"button\"\n                class=\"pf2e-store-tab{{#if isActive}} is-active{{/if}}\"\n                data-action=\"switchStoreTab\" data-store-tab=\"{{type}}\">\n          {{label}} <span class=\"pf2e-store-tab-count\">{{count}}</span>\n        </button>\n      {{/each}}\n    </nav>\n\n    {{#each storeTabs}}\n      {{#if isActive}}\n        {{#each stores}}\n\n          {{#if ../../compactStores}}\n\n            <article class=\"pf2e-store-card pf2e-store-card--compact{{#if closed}} is-closed{{/if}}\" data-store-id=\"{{id}}\">\n              <div class=\"pf2e-store-compact-row\">\n                {{#if closed}}\n                  <span class=\"pf2e-closed-badge\"><i class=\"fa-solid fa-lock\"></i></span>\n                {{/if}}\n                {{#if isBlackMarket}}\n                  <span class=\"pf2e-blackmarket-badge\"><i class=\"fa-solid fa-skull\"></i></span>\n                {{/if}}\n                <input type=\"text\" data-settlement-path=\"stores.{{_globalIndex}}.name\"\n                       value=\"{{name}}\" class=\"pf2e-store-name-input\" />\n                <span class=\"pf2e-store-type-pill\">{{type}}</span>\n                <span class=\"pf2e-store-tier-pill pf2e-store-tier--{{priceTier}}\">{{priceTier}}</span>\n                <span class=\"pf2e-store-compact-owner\">{{owner.name}}</span>\n                {{#if ../../showIncome}}\n                  <span class=\"pf2e-store-compact-balance\">{{income.balance}} gp</span>\n                {{/if}}\n                <button type=\"button\" class=\"pf2e-icon-btn pf2e-icon-btn--danger\"\n                        data-action=\"removeStore\" data-store-id=\"{{id}}\" title=\"Remove store\">\n                  <i class=\"fa-solid fa-trash\"></i>\n                </button>\n              </div>\n            </article>\n\n          {{else}}\n\n            <article class=\"pf2e-store-card{{#if closed}} is-closed{{/if}}\" data-store-id=\"{{id}}\">\n\n              <header class=\"pf2e-store-card-header\">\n                <div class=\"pf2e-store-card-name\">\n                  {{#if closed}}\n                    <span class=\"pf2e-closed-badge\"><i class=\"fa-solid fa-lock\"></i> Bankrupt</span>\n                  {{/if}}\n                  {{#if isBlackMarket}}\n                    <span class=\"pf2e-blackmarket-badge\"><i class=\"fa-solid fa-skull\"></i> Black Market</span>\n                  {{/if}}\n                  <input type=\"text\" data-settlement-path=\"stores.{{_globalIndex}}.name\"\n                         value=\"{{name}}\" class=\"pf2e-store-name-input\" />\n                  <select data-settlement-path=\"stores.{{_globalIndex}}.type\" class=\"pf2e-store-type-select\">\n                    {{#each ../../storeTypeOptions}}\n                      <option value=\"{{value}}\" {{#if (eqStr value ../type)}}selected{{/if}}>{{label}}</option>\n                    {{/each}}\n                  </select>\n                  <select data-settlement-path=\"stores.{{_globalIndex}}.priceTier\" class=\"pf2e-store-tier-select\">\n                    {{#each ../../priceTierOptions}}\n                      <option value=\"{{value}}\" {{#if (eqStr value ../priceTier)}}selected{{/if}}>{{label}}</option>\n                    {{/each}}\n                  </select>\n                  <select data-settlement-path=\"stores.{{_globalIndex}}.districtId\"\n                          data-nullable-str class=\"pf2e-store-district-select\"\n                          title=\"Assign to district\">\n                    <option value=\"\">— No district —</option>\n                    {{#each ../../districts}}\n                      <option value=\"{{id}}\" {{#if (eqStr id ../districtId)}}selected{{/if}}>{{name}}</option>\n                    {{/each}}\n                  </select>\n                  <label class=\"pf2e-store-blackmarket-label\" title=\"Hidden from players; attracts unrest\">\n                    <input type=\"checkbox\" data-settlement-path=\"stores.{{_globalIndex}}.isBlackMarket\"\n                           {{#if isBlackMarket}}checked{{/if}} />\n                    <i class=\"fa-solid fa-skull\"></i>\n                  </label>\n                </div>\n                <div class=\"pf2e-store-card-actions\">\n                  {{#if closed}}\n                    <button type=\"button\" class=\"pf2e-settlement-btn\"\n                            data-action=\"reopenStore\" data-store-id=\"{{id}}\" title=\"Reopen this store\">\n                      <i class=\"fa-solid fa-door-open\"></i> Reopen\n                    </button>\n                  {{/if}}\n                  <button type=\"button\" class=\"pf2e-icon-btn\"\n                          data-action=\"rerollStore\" data-store-id=\"{{id}}\" title=\"Re-roll this store\">\n                    <i class=\"fa-solid fa-dice\"></i>\n                  </button>\n                  <button type=\"button\" class=\"pf2e-icon-btn pf2e-icon-btn--danger\"\n                          data-action=\"removeStore\" data-store-id=\"{{id}}\" title=\"Remove store\">\n                    <i class=\"fa-solid fa-trash\"></i>\n                  </button>\n                </div>\n              </header>\n\n              <div class=\"pf2e-store-grid\">\n\n                <section class=\"pf2e-store-info\">\n                  <div class=\"pf2e-store-owner\">\n                    <label>Owner</label>\n                    <div class=\"pf2e-store-owner-row\">\n                      <input type=\"text\" data-settlement-path=\"stores.{{_globalIndex}}.owner.name\"\n                             data-is-owner=\"true\" value=\"{{owner.name}}\"\n                             title=\"Drop a PF2e actor here to link them as owner\" />\n                      {{#if ownerActor}}\n                        <div class=\"pf2e-npc-chip\">\n                          {{#if ownerActor.portrait}}\n                            <img src=\"{{ownerActor.portrait}}\" class=\"pf2e-npc-chip-portrait\" alt=\"{{ownerActor.name}}\" />\n                          {{/if}}\n                          {{#if ownerActor.level}}\n                            <span class=\"pf2e-npc-chip-level\">Lv {{ownerActor.level}}</span>\n                          {{/if}}\n                          <button type=\"button\" class=\"pf2e-icon-btn\"\n                                  data-action=\"openLinkedActor\" data-actor-id=\"{{owner.actorId}}\" title=\"Open actor sheet\">\n                            <i class=\"fa-solid fa-arrow-up-right-from-square\"></i>\n                          </button>\n                          <button type=\"button\" class=\"pf2e-icon-btn\"\n                                  data-action=\"levelUpActor\" data-actor-id=\"{{owner.actorId}}\" title=\"Level Up actor\">\n                            <i class=\"fa-solid fa-arrow-up\"></i>\n                          </button>\n                        </div>\n                      {{/if}}\n                      <button type=\"button\" class=\"pf2e-icon-btn\"\n                              data-action=\"generateShopkeeper\"\n                              data-store-id=\"{{id}}\" data-staff-id=\"owner\"\n                              title=\"Generate NPC for owner (uses Pf2eNpcMaker if installed)\">\n                        <i class=\"fa-solid fa-wand-magic-sparkles\"></i>\n                      </button>\n                    </div>\n                  </div>\n                  <div class=\"pf2e-store-schedule\">\n                    <label>Weekly Schedule</label>\n                    <table class=\"pf2e-schedule-grid\">\n                      <thead>\n                        <tr>\n                          <th>Day</th><th>Open</th><th>Close</th>\n                          <th title=\"Closed all day\"><i class=\"fa-solid fa-ban\"></i></th>\n                        </tr>\n                      </thead>\n                      <tbody>\n                        {{#each hours.schedule}}\n                          <tr class=\"pf2e-schedule-row{{#if closed}} pf2e-schedule-row--closed{{/if}}\">\n                            <td class=\"pf2e-schedule-day-label\">{{dayLabel}}</td>\n                            <td><input type=\"text\"\n                                  data-settlement-path=\"stores.{{../_globalIndex}}.hours.schedule.{{day}}.open\"\n                                  value=\"{{open}}\" /></td>\n                            <td><input type=\"text\"\n                                  data-settlement-path=\"stores.{{../_globalIndex}}.hours.schedule.{{day}}.close\"\n                                  value=\"{{close}}\" /></td>\n                            <td class=\"pf2e-schedule-closed-cell\">\n                              <input type=\"checkbox\"\n                                     data-settlement-path=\"stores.{{../_globalIndex}}.hours.schedule.{{day}}.closed\"\n                                     {{#if closed}}checked{{/if}} />\n                            </td>\n                          </tr>\n                        {{/each}}\n                      </tbody>\n                    </table>\n                  </div>\n                  {{#if ../../showIncome}}\n                    <div class=\"pf2e-store-income\">\n                      <label>Income</label>\n                      <div class=\"pf2e-store-income-row\">\n                        <span>Balance</span>\n                        <input type=\"number\" data-settlement-path=\"stores.{{_globalIndex}}.income.balance\"  value=\"{{income.balance}}\" />\n                        <span>gp/day</span>\n                        <input type=\"number\" data-settlement-path=\"stores.{{_globalIndex}}.income.dailyAvg\" value=\"{{income.dailyAvg}}\" />\n                        {{#if income.daysInDebt}}\n                          <span class=\"pf2e-debt-counter\" title=\"Days continuously in debt\">\n                            <i class=\"fa-solid fa-triangle-exclamation\"></i> {{income.daysInDebt}}d\n                          </span>\n                        {{/if}}\n                      </div>\n                    </div>\n                  {{/if}}\n                  <div class=\"pf2e-store-market-day\">\n                    <label>Market Day</label>\n                    <select data-settlement-path=\"stores.{{_globalIndex}}.marketWeekday\"\n                            data-nullable-int\n                            class=\"pf2e-store-market-select\"\n                            title=\"Income doubles on this weekday\">\n                      <option value=\"\">— None —</option>\n                      {{#each ../../weekdayOptions}}\n                        <option value=\"{{value}}\" {{#if (eqStr value ../marketWeekday)}}selected{{/if}}>{{label}}</option>\n                      {{/each}}\n                    </select>\n                  </div>\n                </section>\n\n                <section class=\"pf2e-store-staff\">\n                  <header>\n                    <h4>Staff</h4>\n                    <button type=\"button\" class=\"pf2e-icon-btn\"\n                            data-action=\"addStaff\" data-store-id=\"{{id}}\" title=\"Add staff\">\n                      <i class=\"fa-solid fa-user-plus\"></i>\n                    </button>\n                  </header>\n                  {{#if staff.length}}\n                    <ul class=\"pf2e-staff-list\">\n                      {{#each staff}}\n                        <li class=\"pf2e-staff-row\">\n                          <input type=\"text\" class=\"pf2e-staff-name\"\n                                 data-settlement-path=\"stores.{{../_globalIndex}}.staff.{{@index}}.name\"\n                                 data-staff-id=\"{{id}}\"\n                                 value=\"{{name}}\"\n                                 title=\"Drop a PF2e actor here to link them\" />\n                          <input type=\"text\" class=\"pf2e-staff-role\"\n                                 data-settlement-path=\"stores.{{../_globalIndex}}.staff.{{@index}}.role\"\n                                 value=\"{{role}}\" />\n                          <select class=\"pf2e-staff-shift pf2e-staff-shift--{{shift}}\"\n                                  data-settlement-path=\"stores.{{../_globalIndex}}.staff.{{@index}}.shift\">\n                            {{#each ../../../shiftOptions}}\n                              <option value=\"{{value}}\" {{#if (eqStr value ../../shift)}}selected{{/if}}>{{label}}</option>\n                            {{/each}}\n                          </select>\n                          {{#if resolvedActor}}\n                            <div class=\"pf2e-npc-chip pf2e-npc-chip--inline\">\n                              {{#if resolvedActor.portrait}}\n                                <img src=\"{{resolvedActor.portrait}}\" class=\"pf2e-npc-chip-portrait\" alt=\"{{resolvedActor.name}}\" />\n                              {{/if}}\n                              {{#if resolvedActor.level}}\n                                <span class=\"pf2e-npc-chip-level\">{{resolvedActor.level}}</span>\n                              {{/if}}\n                              <button type=\"button\" class=\"pf2e-icon-btn\"\n                                      data-action=\"openLinkedActor\" data-actor-id=\"{{actorId}}\" title=\"Open actor sheet\">\n                                <i class=\"fa-solid fa-arrow-up-right-from-square\"></i>\n                              </button>\n                              <button type=\"button\" class=\"pf2e-icon-btn\"\n                                      data-action=\"levelUpActor\" data-actor-id=\"{{actorId}}\" title=\"Level Up actor\">\n                                <i class=\"fa-solid fa-arrow-up\"></i>\n                              </button>\n                            </div>\n                          {{/if}}\n                          <button type=\"button\" class=\"pf2e-icon-btn\"\n                                  data-action=\"generateShopkeeper\"\n                                  data-store-id=\"{{@../id}}\" data-staff-id=\"{{id}}\"\n                                  title=\"Generate NPC for this worker\">\n                            <i class=\"fa-solid fa-wand-magic-sparkles\"></i>\n                          </button>\n                          <button type=\"button\" class=\"pf2e-icon-btn pf2e-icon-btn--danger\"\n                                  data-action=\"removeStaff\"\n                                  data-store-id=\"{{@../id}}\" data-staff-id=\"{{id}}\" title=\"Remove\">\n                            <i class=\"fa-solid fa-xmark\"></i>\n                          </button>\n                        </li>\n                      {{/each}}\n                    </ul>\n                  {{else}}\n                    <em class=\"pf2e-empty\">No staff listed.</em>\n                  {{/if}}\n                </section>\n\n                <section class=\"pf2e-store-inventory\" data-inventory-drop=\"true\" title=\"Drop a PF2e item here to add it to inventory\">\n                  <header>\n                    <h4>Inventory</h4>\n                    <button type=\"button\" class=\"pf2e-icon-btn\"\n                            data-action=\"generateStoreItem\" data-store-id=\"{{id}}\" data-item-type=\"equipment\"\n                            title=\"Generate item (uses Pf2eItemGenerator if installed)\">\n                      <i class=\"fa-solid fa-flask\"></i>\n                    </button>\n                  </header>\n                  {{#if inventory.length}}\n                    <table class=\"pf2e-inventory-table\">\n                      <thead>\n                        <tr>\n                          <th>Item</th><th>Stock</th><th>Price (gp)</th>\n                          {{#if (neqNum effectiveMul 1)}}\n                            <th title=\"Base price × tier × settlement multiplier\">Effective (gp)</th>\n                          {{/if}}\n                        </tr>\n                      </thead>\n                      <tbody>\n                        {{#each inventory}}\n                          <tr>\n                            <td><input type=\"text\"   data-settlement-path=\"stores.{{../_globalIndex}}.inventory.{{@index}}.name\"  value=\"{{name}}\" /></td>\n                            <td><input type=\"number\" data-settlement-path=\"stores.{{../_globalIndex}}.inventory.{{@index}}.stock\" value=\"{{stock}}\" /></td>\n                            <td><input type=\"number\" data-settlement-path=\"stores.{{../_globalIndex}}.inventory.{{@index}}.price\" value=\"{{price}}\" /></td>\n                            {{#if (neqNum ../effectiveMul 1)}}\n                              <td class=\"pf2e-effective-price\">{{mulNum price ../effectiveMul}}</td>\n                            {{/if}}\n                          </tr>\n                        {{/each}}\n                      </tbody>\n                    </table>\n                  {{else}}\n                    <em class=\"pf2e-empty\">Empty shelves — generate an item above or drop one from the Items sidebar.</em>\n                  {{/if}}\n                </section>\n\n              </div>\n\n            </article>\n\n          {{/if}}\n\n        {{/each}}\n      {{/if}}\n    {{/each}}\n\n  {{else}}\n    <div class=\"pf2e-empty-state\">\n      <i class=\"fa-solid fa-store-slash\"></i>\n      <p>No stores yet — click <em>Add Store</em> above.</p>\n    </div>\n  {{/if}}\n</div>\n"
  };
  for (const _p in _t) {
    if (!(_p in (_Hb.partials ?? {}))) _Hb.registerPartial(_p, _Hb.compile(_t[_p]));
  }
}
